var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`PIONE_ZODIAC_NULL_ALWAYS`,text:{KOREA:`네? 평생을 함께 하자니...... 가, 갑자기 무슨 말씀을 하시는 건지 모르겠군요.`,JPN:`はい？生涯を共に過ごそうとは……い、いきなり何をおっしゃるのか分かりかねます。`,ENG:`Pardon? You want me to be with you for the rest of my life? I-I don't know what you're talking about all of a sudden.`,TWN:`什麼？你說要一輩子在一起……你、你突然間說些什麼，我聽不懂啦。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PIONE_ZODIAC_NULL_ALWAYS`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`PIONE_ZODIAC_NULL_ALWAYS`,text:{KOREA:`아, 계약서...... 말입니까?`,JPN:`ああ、契約書……なのですね？`,ENG:`... Oh, my contract.`,TWN:`啊，你是說……契約書嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PIONE_ZODIAC_NULL_ALWAYS`,face:`UNIT_DESPAIR`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`PIONE_ZODIAC_NULL_ALWAYS`,text:{KOREA:`문제 없습니다. 기사가 누군가를 섬기는 건 지극히 당연한 것이니까요.`,JPN:`問題ありません。騎士たる者、誰かに仕えるのが当たり前なのですから。`,ENG:`No problem. We knights exist to serve someone.`,TWN:`沒問題。騎士侍奉某人，是極其理所當然的事情。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PIONE_ZODIAC_NULL_ALWAYS`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`PIONE_ZODIAC_NULL_ALWAYS`,text:{KOREA:`사장님께선 제가 단장님만큼이나 존중하는 분입니다.`,JPN:`私は社長に対し、団長に対するものと同じだけの敬意を抱いています。`,ENG:`I admire you as much as I admire my captain.`,TWN:`老闆和我們團長一樣，都是我尊敬的人。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PIONE_ZODIAC_NULL_ALWAYS`,face:`UNIT_PRIDE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`PIONE_ZODIAC_NULL_ALWAYS`,text:{KOREA:`사장님께서 추구하시는 이념은 저희가 이루고자 하는 목적과 많이 닮아있습니다.`,JPN:`社長が追い求める理念と、私達が掲げている目的はよく似ているのです。`,ENG:`Your philosophy coincides with our goal in many ways.`,TWN:`老闆所追求的理念與我們要實現的目標十分相似。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PIONE_ZODIAC_NULL_ALWAYS`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`PIONE_ZODIAC_NULL_ALWAYS`,text:{KOREA:`그러니 부디. 부담 갖지 말고, 제게 곁을 맡겨주시길.`,JPN:`だから遠慮なさることはありません。どうぞ気兼ねなく、私達をお側に置いてください。`,ENG:`So, please allow me to serve you from your side.`,TWN:`所以，請不要顧慮，將您的身側交於我吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PIONE_ZODIAC_NULL_ALWAYS`,face:`UNIT_IDLE`},R:null}}}];export{e as default};